using System;
using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// Build test data: 1000 words of varied length
var rng = new Random(42);
var words = new string[1000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    char[] chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var analyzer = new TextAnalyzer(string.Join(' ', words));

Console.WriteLine($"Runtime: {RuntimeInformation.FrameworkDescription}");
Console.WriteLine();

const int warmup = 500;
const int iterations = 5000;

// --- AverageWordLength ---
for (int i = 0; i < warmup; i++) Consume(analyzer.AverageWordLength());
var sw = Stopwatch.StartNew();
for (int i = 0; i < iterations; i++) Consume(analyzer.AverageWordLength());
sw.Stop();
PrintResult("AverageWordLength", sw, iterations);

// --- WordLengthHistogram ---
for (int i = 0; i < warmup; i++) Consume(analyzer.WordLengthHistogram());
sw = Stopwatch.StartNew();
for (int i = 0; i < iterations; i++) Consume(analyzer.WordLengthHistogram());
sw.Stop();
PrintResult("WordLengthHistogram", sw, iterations);

// --- UniqueWordCount ---
for (int i = 0; i < warmup; i++) Consume(analyzer.UniqueWordCount());
sw = Stopwatch.StartNew();
for (int i = 0; i < iterations; i++) Consume(analyzer.UniqueWordCount());
sw.Stop();
PrintResult("UniqueWordCount", sw, iterations);

static void PrintResult(string name, Stopwatch sw, int iterations)
{
    double totalUs = sw.Elapsed.TotalMicroseconds;
    double avgNs = (totalUs / iterations) * 1000;
    Console.WriteLine($"  {name,-25} {avgNs,10:F1} ns/op  ({iterations} ops in {sw.Elapsed.TotalMilliseconds:F1} ms)");
}

[MethodImpl(MethodImplOptions.NoInlining)]
static void Consume<T>(T value) { }

